use crate::decoders::{Crack, CrackResult, Decoder, check_string_success};use crate::checkers::CheckerTypes;use std::marker::PhantomData;pub struct VigenereDecoder;fn vigenere_decode(text: &str, key: &str) -> String {    let key = key.to_uppercase();    let key_bytes: Vec<u8> = key.bytes().collect();    if key_bytes.is_empty() {        return text.to_string();    }    let mut key_idx = 0;    text.chars().map(|c| {        if c.is_ascii_uppercase() {            let shift = key_bytes[key_idx % key_bytes.len()] - b'A';            key_idx += 1;            let decoded = ((c as u8 - b'A' + 26 - shift) % 26) + b'A';            decoded as char        } else if c.is_ascii_lowercase() {            let shift = key_bytes[key_idx % key_bytes.len()] - b'A';            key_idx += 1;            let decoded = ((c as u8 - b'a' + 26 - shift) % 26) + b'a';            decoded as char        } else {            c        }    }).collect()}fn generate_keys(max_len: usize) -> Vec<String> {    let common_keys = vec!["KEY", "SECRET", "CIPHER", "CODE", "PASSWORD", "ABCDEFGHIJKLMNOPQRSTUVWXYZ"];    let mut keys: Vec<String> = common_keys.iter().map(|s| s.to_string()).collect();    for len in 1..=max_len.min(4) {        if len == 1 {            for c in b'A'..=b'Z' {                let s = String::from_utf8(vec![c]).unwrap();                if !keys.contains(&s) {                    keys.push(s);                }            }        }    }    keys}impl Crack for Decoder<VigenereDecoder> {    fn crack(&self, text: &str, checker: &CheckerTypes) -> CrackResult {        let mut result = CrackResult::new(self.get_name(), self.get_description(), self.get_link());        result.encrypted_text = text.to_string();        let keys = generate_keys(3);        for key in &keys {            let decoded = vigenere_decode(text, key);            if check_string_success(&decoded, text) {                let check_result = checker.check_text(&decoded);                if check_result.is_identified {                    result.success = true;                    result.unencrypted_text = Some(vec![decoded]);                    result.key = Some(key.clone());                    result.checker_name = check_result.checker_name;                    return result;                }            }        }        result    }    fn get_name(&self) -> &'static str { "Vigenere" }    fn get_popularity(&self) -> f32 { 0.5 }    fn get_tags(&self) -> &'static [&'static str] { &["vigenere", "decoder", "cipher", "classical"] }    fn get_description(&self) -> &'static str { "Vigenere cipher uses a keyword to shift each letter by a different amount." }    fn get_link(&self) -> &'static str { "https://en.wikipedia.org/wiki/Vigen%C3%A8re_cipher" }}impl Decoder<VigenereDecoder> {    pub fn new() -> Self {        Decoder {            name: "Vigenere",            description: "Vigenere cipher uses a keyword to shift each letter by a different amount.",            link: "https://en.wikipedia.org/wiki/Vigen%C3%A8re_cipher",            tags: vec!["vigenere", "decoder", "cipher", "classical"],            popularity: 0.5,            phantom: PhantomData,        }    }}



